/**
 * Tests for ReaderTopBarMenuHelper focusing on custom lists display logic
 * Verifies that lists are shown directly in menu when there are 2 or fewer,
 * and in a submenu when there are more than 2.
 */
class ReaderTopBarMenuHelperCustomListsTest {
    private val readerTagsFeedFeatureConfig: ReaderTagsFeedFeatureConfig = mock()
    private val helper = ReaderTopBarMenuHelper(
        readerTagsFeedFeatureConfig = readerTagsFeedFeatureConfig
    )

    @Test
    fun `GIVEN 1 custom list WHEN createMenu THEN list is shown directly in menu root`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("My List")) // item 2
        }

        val menu = helper.createMenu(tags)

        // Should have a divider
        assertThat(menu).contains(MenuElementData.Divider)

        // Should NOT have a submenu for lists
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNull()

        // The custom list should be directly in the menu
        val customListItem = menu.findSingleItem { it.id == "2" }
        assertThat(customListItem).isNotNull
        assertThat(customListItem!!.text).isEqualTo(UiStringText("My List"))
    }

    @Test
    fun `GIVEN 2 custom lists WHEN createMenu THEN lists are shown directly in menu root`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("List One")) // item 2
            add(createCustomListTag("List Two")) // item 3
        }

        val menu = helper.createMenu(tags)

        // Should have a divider
        assertThat(menu).contains(MenuElementData.Divider)

        // Should NOT have a submenu for lists
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNull()

        // Both custom lists should be directly in the menu
        val customList1Item = menu.findSingleItem { it.id == "2" }
        assertThat(customList1Item).isNotNull
        assertThat(customList1Item!!.text).isEqualTo(UiStringText("List One"))

        val customList2Item = menu.findSingleItem { it.id == "3" }
        assertThat(customList2Item).isNotNull
        assertThat(customList2Item!!.text).isEqualTo(UiStringText("List Two"))
    }

    @Test
    fun `GIVEN 3 custom lists WHEN createMenu THEN lists are shown in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("List One")) // item 2
            add(createCustomListTag("List Two")) // item 3
            add(createCustomListTag("List Three")) // item 4
        }

        val menu = helper.createMenu(tags)

        // Should have a divider
        assertThat(menu).contains(MenuElementData.Divider)

        // Should have a submenu for lists
        val customListsSubMenu = menu.findSubMenu()
        assertThat(customListsSubMenu).isNotNull
        assertThat(customListsSubMenu!!.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_lists))

        // Lists should be in the submenu
        val customList1Item = customListsSubMenu.children.findSingleItem { it.id == "2" }
        assertThat(customList1Item).isNotNull
        assertThat(customList1Item!!.text).isEqualTo(UiStringText("List One"))

        val customList2Item = customListsSubMenu.children.findSingleItem { it.id == "3" }
        assertThat(customList2Item).isNotNull
        assertThat(customList2Item!!.text).isEqualTo(UiStringText("List Two"))

        val customList3Item = customListsSubMenu.children.findSingleItem { it.id == "4" }
        assertThat(customList3Item).isNotNull
        assertThat(customList3Item!!.text).isEqualTo(UiStringText("List Three"))

        // Lists should NOT be directly in the root menu
        val directList1 = menu.findSingleItem { it.id == "2" }
        val directList2 = menu.findSingleItem { it.id == "3" }
        val directList3 = menu.findSingleItem { it.id == "4" }
        assertThat(directList1).isNull()
        assertThat(directList2).isNull()
        assertThat(directList3).isNull()
    }

    @Test
    fun `GIVEN 2 custom lists WHEN getReaderTagIndexFromMenuItem THEN return correct indices`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("List One")) // item 2
            add(createCustomListTag("List Two")) // item 3
        }

        val menu = helper.createMenu(tags)

        val customList1Item = menu.findSingleItem { it.text == UiStringText("List One") }!!
        assertThat(helper.getReaderTagIndexFromMenuItem(customList1Item)).isEqualTo(2)

        val customList2Item = menu.findSingleItem { it.text == UiStringText("List Two") }!!
        assertThat(helper.getReaderTagIndexFromMenuItem(customList2Item)).isEqualTo(3)
    }

    private fun List<MenuElementData>.findSingleItem(
        predicate: (MenuElementData.Item.Single) -> Boolean
    ): MenuElementData.Item.Single? {
        return find { it is MenuElementData.Item.Single && predicate(it) } as? MenuElementData.Item.Single
    }

    private fun List<MenuElementData>.findSubMenu(): MenuElementData.Item.SubMenu? {
        return find { it is MenuElementData.Item.SubMenu } as? MenuElementData.Item.SubMenu
    }

    private fun mockDiscoverTag(): ReaderTag {
        return mock {
            on { isDiscover }.thenReturn(true)
        }
    }

    private fun mockFollowingTag(): ReaderTag {
        return mock {
            on { isFollowedSites }.thenReturn(true)
        }
    }

    private fun createCustomListTag(title: String): ReaderTag {
        return ReaderTag(
            title,
            title,
            title,
            "http://endpoint.com",
            ReaderTagType.CUSTOM_LIST
        )
    }
}
